// services/taskService.js
import axios from "axios";

const API_URL = "http://localhost:5002/api/tasks";

// 🔹 GET tasks by project
export const getTasksByProject = async (projectId) => {
  const res = await axios.get(`${API_URL}/project/${projectId}`);
  return res.data;
};

// 🔹 CREATE
export const createTask = async (taskData) => {
  const res = await axios.post(API_URL, taskData);
  return res.data;
};

// 🔹 DELETE
export const deleteTask = async (taskId) => {
  const res = await axios.delete(`${API_URL}/${taskId}`);
  return res.data;
};

// 🔹 UPDATE STATUS
export const updateTaskStatus = async (taskId, status) => {
  const res = await axios.patch(`${API_URL}/${taskId}/status`, { status });
  return res.data;
};

// 🔹 UPDATE TASK
export const updateTask = async (taskId, data) => {
  const res = await axios.put(`${API_URL}/${taskId}`, data);
  return res.data;
};

// 🔹 ASSIGN USER
export const assignTaskToUser = async (taskId, assignedTo) => {
  const res = await axios.patch(`${API_URL}/${taskId}/assign`, {
    assignedTo,
  });
  return res.data;
};

// 🔹 COMMENT
export const addCommentToTask = async (taskId, comment) => {
  const res = await axios.post(`${API_URL}/${taskId}/comments`, comment);
  return res.data;
};

// 🔹 FILE
export const uploadTaskFile = async (taskId, file) => {
  const formData = new FormData();
  formData.append("file", file);

  const res = await axios.post(`${API_URL}/${taskId}/upload`, formData, {
    headers: { "Content-Type": "multipart/form-data" },
  });

  return res.data;
};
